//! `baton-put` logic: stream a local file up to an iRODS data object.
//!
//! Symmetric with `baton-get --save`: the input record names the
//! iRODS destination via `collection` + `data_object` and the local
//! source path via the `json_to_local_path` priority
//! (`baton/src/json.c:1211-1244`):
//!
//! 1. `<directory>/<file>` if both are present
//! 2. `<directory>/<data_object>` if `file` is absent
//! 3. `./<file>` if `directory` is absent but `file` is present
//! 4. `./<data_object>` if neither is present
//!
//! `file` is preferred over `data_object` for the local basename;
//! renaming on the iRODS side stays the `data_object` field.
//!
//! `--checksum` populates the output `checksum` field with iRODS's
//! post-close digest. `--verify` additionally hashes bytes
//! client-side as they stream up and compares against iRODS's
//! digest after close — mismatch surfaces as an in-band annotated
//! error. `--verify` implies `--checksum` on the output: the digest
//! is in hand by the time we compare, and dropping it would be
//! arbitrary.
//!
//! The MD5 here is an **integrity check** matching the digest iRODS
//! stores in its catalog — not a cryptographic claim. MD5 is broken
//! for adversarial-collision resistance, but the threat model for
//! `--verify` is detecting accidental corruption (network bit-flip,
//! disk error, partial write) by an honest client / server. SHA2
//! support is tracked in #31; the matrix coverage is in #27.

use std::fs::File;
use std::io::Read;
use std::path::PathBuf;

use crate::connection::{OpenMode, RodsConnection};
use crate::error::BatonError;
use crate::types::Target;

/// Caller-controlled flags for [`put_one`].
#[derive(Debug, Default, Clone, Copy)]
pub struct PutOptions {
    /// Compute and record a server-side checksum after the upload
    /// completes via `rcDataObjChksum`; populated on the output
    /// `checksum` field. The format depends on the server hash
    /// scheme — bare 32-char hex for MD5 (the client default pinned
    /// for issue #25), `sha2:<base64>` for SHA2.
    pub checksum: bool,

    /// Compute MD5 client-side as bytes are streamed up, compare
    /// against the server's digest after close, and surface any
    /// mismatch as a per-input error. Implies the `checksum` flag's
    /// effect on the output (the field is populated whether or not
    /// the verify step is also requested).
    pub verify: bool,
}

// Same chunk size as the read path — keeps memory pressure
// predictable across get/put and lets the future streaming-MD5 path
// hash exactly the bytes that were written.
const WRITE_CHUNK_SIZE: usize = 64 * 1024;

/// Stream a local file up to an iRODS data object.
///
/// Required input fields:
///   - `collection`: target iRODS collection
///   - `data_object`: target name on the iRODS side
///
/// Optional input fields:
///   - `directory`: local source directory (defaults to the
///     process cwd if absent)
///   - `file`: local file name (defaults to `data_object` if absent)
///
/// The local source path is built per upstream's
/// `json_to_local_path` priority — see the module-level doc.
///
/// The output is the input record echoed back, with `checksum`
/// populated when `opts.checksum` or `opts.verify` is set. On a
/// `--verify` mismatch the bytes are left on the server (baton-rs
/// follows upstream baton in not auto-cleaning failed verifies); the
/// caller gets a `BatonError` whose message names both digests.
///
/// Collections are an error: there's nothing to put for a
/// collection. Matches the symmetric behaviour of [`crate::operations::get::get_one`].
pub fn put_one(
    conn: &mut RodsConnection,
    target: Target,
    opts: &PutOptions,
) -> Result<Target, BatonError> {
    let path = target.path();
    let mut data_obj = match target {
        Target::DataObject(d) => d,
        Target::Collection(c) => {
            // -310000 USER_FILE_DOES_NOT_EXIST. Extendo's
            // `Archive a DataObject when archiving a collection`
            // test (`data_object_test.go:317`) asserts on the
            // iRODS code. Wire-shape align with upstream baton.
            return Err(BatonError::from_irods_with_context(
                -310000,
                &format!(
                    "baton-put: target is a collection, not a data object: {}",
                    c.collection
                ),
            ));
        }
    };

    // Path priority mirrors `json_to_local_path` in
    // `baton/src/json.c:1211-1244`. `directory` defaults to "."
    // (cwd) and `file` is preferred over `data_object` for the
    // local basename.
    let directory = data_obj.directory.as_deref().unwrap_or(".");
    let basename = data_obj
        .file
        .as_deref()
        .unwrap_or(&data_obj.data_object);
    let mut local_path = PathBuf::from(directory);
    local_path.push(basename);

    let mut file = File::open(&local_path).map_err(|e| {
        // -310000 USER_FILE_DOES_NOT_EXIST. Extendo's
        // `Put a directory without recursion` test
        // (`client_test.go:633`) sends a directory path here,
        // which `File::open` rejects with `IsADirectory`.
        BatonError::from_irods_with_context(
            -310000,
            &format!(
                "could not open local file {}: {}",
                local_path.display(),
                e
            ),
        )
    })?;

    // Client-side MD5 is only computed when --verify is set. Allocate
    // the hashing context up front so the streamer can update it in
    // place chunk by chunk rather than going back over the bytes
    // afterwards.
    let mut hash = if opts.verify {
        Some(md5::Context::new())
    } else {
        None
    };

    let handle = conn.open_data_object(&path, OpenMode::Write)?;
    let stream_result = stream_file_to_handle(conn, handle, &mut file, hash.as_mut());
    // Close on every path. iRODS server-side state for the L1
    // descriptor lives until close; failing to close on the error
    // path would leak the descriptor for the lifetime of the
    // connection.
    let close_result = conn.close_data_object(handle);
    stream_result?;
    close_result?;

    // Server-side checksum runs after close — `rcDataObjChksum`
    // operates on the catalog state, not the in-flight L1 descriptor.
    // --verify implies --checksum on the output: once we've asked the
    // server for its digest there's no reason to drop it on the
    // floor, and the user gets one less flag combination to remember.
    if opts.checksum || opts.verify {
        // Force a compute-on-all-replicas. flags=0 (read-only) was
        // sufficient when puts landed on a single-replica resource
        // (`testResc`) — iRODS's auto-compute on read-flagless was
        // enough there. With the env's default resource honoured
        // (now `replResc` on the CI images, see the shim's
        // `DEF_RESC_NAME_KW` pass in `shim_data_obj_open`), puts
        // create multiple stale replicas and a read-only call
        // returns an empty digest. CHKSUM_ALL_KW + FORCE makes
        // iRODS populate every replica's checksum before we read
        // it back. Matches upstream baton's behaviour (`write.c:119-122`
        // adds REG_CHKSUM_KW atomically on `rcDataObjPut`; baton-rs
        // uses the lower-level open + write + close API and so has
        // to compute as a separate step).
        let flags =
            crate::ffi::SHIM_CHKSUM_CALCULATE | crate::ffi::SHIM_CHKSUM_FORCE;
        let server_chksum = conn.checksum_data_object(&path, flags)?;
        if let Some(ctx) = hash {
            // `ctx.finalize()` consumes the context and returns a
            // Digest that formats as 32 lowercase hex via {:x}.
            // (Renamed from `compute()` in md5 0.8 — bumped via #46.)
            let client_hex = format!("{:x}", ctx.finalize());
            // verify_checksum returns Err on mismatch; the caller
            // (put_one_annotated, in the binary's NDJSON loop)
            // surfaces it as an in-band annotation. The mismatched
            // bytes are left on the server — baton-rs follows
            // upstream baton in not auto-cleaning failed verifies.
            // The error message carries both digests for diagnosis.
            super::verify_checksum(&client_hex, &server_chksum, "put")?;
        }
        // Reached only on --checksum-only or on a successful --verify.
        data_obj.checksum = Some(server_chksum);
    }

    Ok(Target::DataObject(data_obj))
}

/// Same as [`put_one`], but catches iRODS errors and emits the input
/// annotated with an `"error"` field instead of propagating. Mirrors
/// `get_one_annotated` so binaries can keep their NDJSON loops uniform.
pub fn put_one_annotated(
    conn: &mut RodsConnection,
    target: Target,
    opts: &PutOptions,
) -> Target {
    super::annotate_failure(target, |t| put_one(conn, t, opts))
}

/// Read `file` chunk by chunk and write each chunk into `handle`.
/// Stops at EOF (zero-byte read) on the local side. Short writes from
/// `write_data_object` are re-issued for the remainder, even though
/// iRODS doesn't typically short-write — defensive for when iRODS's
/// internals change.
///
/// When `hash` is `Some`, each chunk is fed into the MD5 context
/// before it's written, so the same byte sequence that goes to iRODS
/// is hashed on the client side. The single-pass design avoids
/// re-reading the file for the verify path.
fn stream_file_to_handle<R: Read>(
    conn: &mut RodsConnection,
    handle: i32,
    file: &mut R,
    mut hash: Option<&mut md5::Context>,
) -> Result<(), BatonError> {
    let mut buf = vec![0u8; WRITE_CHUNK_SIZE];
    loop {
        let n = file.read(&mut buf).map_err(|e| {
            // -310000 USER_FILE_DOES_NOT_EXIST — local-FS error
            // family. Mid-stream read failure is rare but the
            // wire shape should match the file-open code.
            BatonError::from_irods_with_context(
                -310000,
                &format!("reading local file: {}", e),
            )
        })?;
        if n == 0 {
            break;
        }
        if let Some(h) = hash.as_deref_mut() {
            h.consume(&buf[..n]);
        }
        let mut written = 0;
        while written < n {
            let m = conn.write_data_object(handle, &buf[written..n])?;
            if m == 0 {
                return Err(BatonError {
                    code: -1,
                    message: "rcDataObjWrite accepted 0 bytes; aborting to avoid spinning"
                        .to_string(),
                });
            }
            written += m;
        }
    }
    Ok(())
}

